#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int calculateSumOfSubarrayMinimums(int* inputArray, int inputArrayLength) {
    int* left = (int*)malloc(inputArrayLength * sizeof(int));
    int* right = (int*)malloc(inputArrayLength * sizeof(int));
    int* stack = (int*)malloc(inputArrayLength * sizeof(int));
    int top = -1;
    long long result = 0;
    for (int i = 0; i < inputArrayLength; i++) {
        while (top >= 0 && inputArray[stack[top]] > inputArray[i]) top--;
        left[i] = top == -1 ? i + 1 : i - stack[top];
        stack[++top] = i;
    }
    top = -1;
    for (int i = inputArrayLength - 1; i >= 0; i--) {
        while (top >= 0 && inputArray[stack[top]] >= inputArray[i]) top--;
        right[i] = top == -1 ? inputArrayLength - i : stack[top] - i;
        stack[++top] = i;
    }
    for (int i = 0; i < inputArrayLength; i++) {
        result = (result + (long long)left[i] * right[i] * inputArray[i]) % MOD;
    }
    free(left);
    free(right);
    free(stack);
    return (int)result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* inputArray = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &inputArray[i]);
        }
        printf("%d\n", calculateSumOfSubarrayMinimums(inputArray, N));
        free(inputArray);
    }
    return 0;
}

