const int MOD = 1e9 + 7;

int calculateSumOfSubarrayMinimums(vector<int>& inputArray) {
    int inputArrayLength = inputArray.size();
    vector<int> left(inputArrayLength), right(inputArrayLength);
    stack<int> s;
    for (int i = 0; i < inputArrayLength; i++) {
        while (!s.empty() && inputArray[s.top()] > inputArray[i]) s.pop();
        left[i] = s.empty() ? i + 1 : i - s.top();
        s.push(i);
    }
    while (!s.empty()) s.pop();
    for (int i = inputArrayLength - 1; i >= 0; i--) {
        while (!s.empty() && inputArray[s.top()] >= inputArray[i]) s.pop();
        right[i] = s.empty() ? inputArrayLength - i : s.top() - i;
        s.push(i);
    }
    long long result = 0;
    for (int i = 0; i < inputArrayLength; i++) {
        result = (result + (long long)left[i] * right[i] * inputArray[i]) % MOD;
    }
    return (int)result;
}

