import java.util.Stack;
public class Main {
    public static int calculateSumOfSubarrayMinimums(int[] inputArray) {
        int inputArrayLength = inputArray.length;
        int[] left = new int[inputArrayLength];
        int[] right = new int[inputArrayLength];
        Stack<Integer> s = new Stack<>();
        for (int i = 0; i < inputArrayLength; i++) {
            while (!s.isEmpty() && inputArray[s.peek()] > inputArray[i]) s.pop();
            left[i] = s.isEmpty() ? i + 1 : i - s.peek();
            s.push(i);
        }
        while (!s.isEmpty()) s.pop();
        for (int i = inputArrayLength - 1; i >= 0; i--) {
            while (!s.isEmpty() && inputArray[s.peek()] >= inputArray[i]) s.pop();
            right[i] = s.isEmpty() ? inputArrayLength - i : s.peek() - i;
            s.push(i);
        }
        long result = 0;
        for (int i = 0; i < inputArrayLength; i++) {
            result = (result + (long)left[i] * right[i] * inputArray[i]) % (int)(1e9 + 7);
        }
        return (int)result;
    }

    public static void main(String[] args) {
        java.util.Scanner sc = new java.util.Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] inputArray = new int[N];
            for (int i = 0; i < N; i++) {
                inputArray[i] = sc.nextInt();
            }
            System.out.println(calculateSumOfSubarrayMinimums(inputArray));
        }
    }
}

