    let res = 0;
    let left = new Array(inputArray.length);
    let right = new Array(inputArray.length);
    let stack = [];
    for (let i = 0; i < inputArray.length; i++) {
        while (stack.length && inputArray[stack[stack.length - 1]] > inputArray[i]) stack.pop();
        left[i] = stack.length ? i - stack[stack.length - 1] : i + 1;
